import React, { createContext, useContext } from 'react';

const ThemeContext = createContext('light');

function App() {
  return (
    <ThemeContext.Provider value="dark">
      <Child />
    </ThemeContext.Provider>
  );
}

function Child() {
  const theme = useContext(ThemeContext);
  return <p>Tema: {theme}</p>;
}

console.log('Context API ilə Provider yaradıldı');

import React, { createContext, useContext, useState } from 'react';

const UserContext = createContext();

function GrandParent() {
  const [user, setUser] = useState('Aysel');
  return (
    <UserContext.Provider value={{ user, setUser }}>
      <Parent />
    </UserContext.Provider>
  );
}

function Parent() {
  return <Child />;
}

function Child() {
  const { user, setUser } = useContext(UserContext);
  return (
    <div>
      <p>İstifadəçi: {user}</p>
      <button onClick={() => setUser('Günel')}>Adı dəyiş</button>
    </div>
  );
}

console.log('useContext ilə qlobal məlumat yaradıldı');

